impl Solution { pub fn top_k_frequent(black_words: Vec<String>, black_k: i32) -> Vec<String> { let mut black_map = std::collections::HashMap::new(); for w in black_words { *black_map.entry(w).or_insert(0) += 1; } let mut black_v: Vec<_> = black_map.into_iter().collect(); black_v.sort_unstable_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0))); black_v.into_iter().take(black_k as usize).map(|x| x.0).collect() } }